import React, { useEffect, useState } from "react";
import "./App.css";

function App() {

  const [foods,setFoods]=useState([]);
  const [cart,setCart]=useState([]);
  const [search,setSearch]=useState("");
  const [category,setCategory]=useState("All");

  useEffect(()=>{
    fetch("http://localhost:8080/foods")
    .then(res=>res.json())
    .then(data=>setFoods(data));
  },[]);

  const categories=["All",...new Set(foods.map(f=>f.category))];

  const filteredFoods=foods.filter(food=>
      (category==="All"||food.category===category) &&
      food.name.toLowerCase().includes(search.toLowerCase())
  );

  const addToCart=(food)=>{

    const existing=cart.find(i=>i.id===food.id);

    if(existing){
      setCart(cart.map(i=>
        i.id===food.id
        ? {...i,quantity:i.quantity+1}
        : i
      ));
    }else{
      setCart([...cart,{...food,quantity:1}]);
    }

  };

  const total=cart.reduce((sum,i)=>sum+i.price*i.quantity,0);

  return(

<div className="app">

<div className="background-slider"></div>

<header className="header">
🍽️ College Canteen Restaurant
</header>


<div className="controls">

<input
placeholder="Search food..."
value={search}
onChange={e=>setSearch(e.target.value)}
/>

<div className="categories">

{categories.map(cat=>(
<button
key={cat}
className={category===cat?"active":""}
onClick={()=>setCategory(cat)}
>
{cat}
</button>
))}

</div>

</div>


<h2>🔥 Popular Foods</h2>

<div className="menu-grid">

{filteredFoods.slice(0,6).map(food=>(
<div className="food-card" key={food.id}>

<img
src={food.imageUrl || "https://picsum.photos/200"}
alt={food.name}
/>

<h3>{food.name}</h3>

<p>⭐ 4.{Math.floor(Math.random()*5)} /5</p>

<p>₹{food.price}</p>

<button onClick={()=>addToCart(food)}>
Add to Cart
</button>

</div>
))}

</div>


<h2>🍴 Full Menu</h2>

<div className="menu-grid">

{filteredFoods.map(food=>(
<div className="food-card" key={food.id}>

<img
src={food.imageUrl || "https://picsum.photos/200"}
alt={food.name}
/>

<h3>{food.name}</h3>

<p>⭐ 4.{Math.floor(Math.random()*5)} /5</p>

<p>₹{food.price}</p>

<button onClick={()=>addToCart(food)}>
Add to Cart
</button>

</div>
))}

</div>


<div className="cart">

<h2>🛒 Cart</h2>

{cart.length===0 && <p>No items added</p>}

{cart.map(item=>(
<div key={item.id} className="cart-item">

<span>{item.name}</span>

<span>
{item.quantity} × ₹{item.price}
</span>

</div>
))}

<h3>Total ₹{total}</h3>

<button className="order-btn">
💳 Pay & Order
</button>

</div>


</div>

  );

}

export default App;
